    let cmpResult: bigint;
    switch (op) {
      case "<":
        cmpResult = BigInt(left.value) < BigInt(right.value) ? 1n : 0n;
        break;
      case ">":
        cmpResult = BigInt(left.value) > BigInt(right.value) ? 1n : 0n;
        break;
      case "<=":
        cmpResult = BigInt(left.value) <= BigInt(right.value) ? 1n : 0n;
        break;
      case ">=":
        cmpResult = BigInt(left.value) >= BigInt(right.value) ? 1n : 0n;
        break;
      case "==":
        cmpResult = BigInt(left.value) === BigInt(right.value) ? 1n : 0n;
        break;
      case "!=":
        cmpResult = BigInt(left.value) !== BigInt(right.value) ? 1n : 0n;
        break;
